#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[101];
        scanf("%s", S);
        int len = strlen(S);
        if (len == 2) {
            printf("YES\n");
            continue;
        }
        char a = S[0], b = S[1];
        if (a == b) {
            printf("NO\n");
            continue;
        }
        int flag = 1;
        for (int i = 2; i < len; i++) {
            if (i % 2 == 0) {
                if (S[i] != a) {
                    flag = 0;
                    break;
                }
            } else {
                if (S[i] != b) {
                    flag = 0;
                    break;
                }
            }
        }
        if (flag) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

